    'repubblica_italiana' => 
    array (
      'title' => 'República Italiana',
      'lead' => 'La monetazione della Repubblica Italiana.',
      'blocks' => 
      array (
        0 => 
        array (
          'type' => 'figure',
          'image' => 
          array (
            'file' => 'repubblica_italiana.png',
            'alt' => '',
