    'tetradrachm_alexander' => 
    array (
      'title' => 'El tetradracma de Alejandro Magno',
      'lead' => 'La monetazione di Alessandro Magno.',
      'blocks' => 
      array (
        0 => 
        array (
          'type' => 'figure',
          'image' => 
