    'florin' => 
    array (
      'title' => 'El florìn',
      'lead' => 'Il fiorino fiorentino e la sua storia.',
      'blocks' => 
      array (
        0 => 
        array (
          'type' => 'figure',
          'image' => 
          array (
            'file' => 'fiorinoa.jpg',
            'alt' => '',
