    'taler' => 
    array (
      'title' => 'El Thaler',
      'lead' => 'Il tallero nelle zecche europee.',
      'blocks' => 
      array (
        0 => 
        array (
          'type' => 'figure',
          'image' => 
          array (
            'file' => 'talleroa.jpg',
            'alt' => '',
